<script>
document.addEventListener('DOMContentLoaded', function() {
	const salary1 = document.getElementById('salary_1');
	const salary2 = document.getElementById('salary_2');
	const result = document.getElementById('borrowCalcResult');
	const amount = document.getElementById('borrowCalcAmount');

	if (!salary1 || !salary2 || !result || !amount) return;

	const formatCurrency = (value) => {
		const roundedValue = Math.round(Number(value) || 0);

		return new Intl.NumberFormat('en-GB', {
			style: 'currency',
			currency: 'GBP',
			minimumFractionDigits: 0,
			maximumFractionDigits: 0
		}).format(roundedValue).replace(/\.\d+$/, '');
	};

	const parseNumber = (value) => {
		return parseFloat(String(value).replace(/,/g, '').replace(/[^\d.]/g, '')) || 0;
	};

	const formatWithCommas = (value) => {
		const number = parseNumber(value);
		if (number === 0) return '';
		return new Intl.NumberFormat('en-GB', {
			maximumFractionDigits: 0
		}).format(number);
	};

	const updateBorrowAmount = () => {
		const mainSalary = parseNumber(salary1.value);
		const secondarySalary = parseNumber(salary2.value);
		const totalIncome = mainSalary + secondarySalary;

		const minBorrow = Math.round(totalIncome * 3.2);
		const maxBorrow = Math.round(totalIncome * 4.5);

		amount.innerHTML =
			`${formatCurrency(minBorrow).replace(/\.\d+$/, '')}<br>to ${formatCurrency(maxBorrow).replace(/\.\d+$/, '')}`;
		result.style.display = 'block';
	};

	const handleFormattedInput = (input) => {
		input.addEventListener('input', function() {
			const cursorStart = this.selectionStart;
			const oldLength = this.value.length;

			let rawValue = this.value.replace(/[^\d]/g, '');

			if (rawValue === '') {
				this.value = '';
				updateBorrowAmount();
				return;
			}

			this.value = new Intl.NumberFormat('en-GB').format(parseInt(rawValue, 10));

			const newLength = this.value.length;
			const newCursor = cursorStart + (newLength - oldLength);

			this.setSelectionRange(newCursor, newCursor);
			updateBorrowAmount();
		});

		input.addEventListener('blur', function() {
			if (this.value.trim() === '') {
				this.value = '';
			} else {
				this.value = formatWithCommas(this.value);
			}
			updateBorrowAmount();
		});
	};

	const formatMortgageInputs = () => {
		const mortgageInputs = document.querySelectorAll(
			'.mortgage-calculators .right input[type="text"], .mortgage-calculators .right input[type="number"]'
		);

		mortgageInputs.forEach((input) => {
			input.setAttribute('inputmode', 'numeric');

			input.addEventListener('input', function() {
				const cursorStart = this.selectionStart;
				const oldLength = this.value.length;

				let rawValue = this.value.replace(/[^\d]/g, '');

				if (rawValue === '') {
					this.value = '';
					return;
				}

				this.value = new Intl.NumberFormat('en-GB').format(parseInt(rawValue, 10));

				const newLength = this.value.length;
				const newCursor = cursorStart + (newLength - oldLength);

				this.setSelectionRange(newCursor, newCursor);
			});
		});
	};

	formatMortgageInputs();





	handleFormattedInput(salary1);
	handleFormattedInput(salary2);

	// Start empty, not prefilled
	salary1.value = '50,000';
	salary2.value = '';
	updateBorrowAmount();
});

document.addEventListener('DOMContentLoaded', function() {
	const repaymentInput = document.querySelector('.mortgage-calculators .right input[name="repayment"]');

	if (!repaymentInput) return;

	const descriptor = Object.getOwnPropertyDescriptor(HTMLInputElement.prototype, 'value');

	Object.defineProperty(repaymentInput, 'value', {
		get() {
			return descriptor.get.call(this);
		},
		set(value) {
			if (typeof value === 'string') {
				value = value.replace(/^([\d,]+)\.\d+$/, '$1');
			}

			descriptor.set.call(this, value);
		}
	});
});
</script>